<template>
	<view class="news">
		<view class="news-tab">
			<scroll-view class="news-tab-scroll" scroll-x="true" scroll-with-animation>
				<view class="news-tab-scroll-box" v-for="(item,index) in news.list" :key="item.id" @click="id=item.id"
					:class="id==item.id?'active':''">
					<text class="news-tab-scroll-box-text" :class="index!=5?'line':''">{{item.name}}</text>
				</view>
			</scroll-view>
		</view>
		<view class="news-element">
			<view v-for="(item,index) in all.list" :key="index" class="news-element-box" v-if="item.type==id"  @tap="TapNew(item.id)">
				<image :src="ip+item.cover" mode=""></image>
				<text>{{item.title}}</text>
			</view>
		</view>
	</view>
</template>

<script>
	export default {
		data() {
			return {
				id: 9,
				ip: 'http://10.20.18.2:10001',
				news: {
					list: []
				},
				all: {
					list: []
				}
			}
		},
		methods: {
			getNews() {
				uni.request({
					url: this.ip + '/prod-api/press/category/list',
					success: (res) => {
						this.news.list = res.data.data
					}
				})
			},
			getAll() {
				uni.request({
					url: this.ip + '/prod-api/press/press/list',
					success: (res) => {
						this.all.list = res.data.rows
					}
				})
			},
			TapNew(e){
				uni.navigateTo({
					url: '/pages/News/NewsElement?id='+e,
				})
			}
		},
		mounted() {
			this.getNews();
			this.getAll();
		}
	}
</script>

<style lang="scss">
	.news {
		display: flex;
		flex-direction: column;

		.news-tab {
			border-bottom: 8rpx solid #ececec;

			.news-tab-scroll {
				height: 100rpx;
				white-space: nowrap;

				.news-tab-scroll-box {
					height: 100rpx;
					padding: 0 20rpx;
					display: inline-block;
					text-align: center;

					&.active {
						color: red;
					}

					.news-tab-scroll-box-text {
						font-size: 30rpx;
						line-height: 100rpx;
						padding-right: 40rpx;

						&.line {
							border-right: 1rpx solid #000;
						}
					}
				}
			}
		}

		.news-element {
			.news-element-box {
				display: block;
				height: 200rpx;
				border-bottom: 1rpx solid #bdbdbd;

				image {
					float: left;
					width: 20%;
					height: 80%;
					padding: 20rpx;
				}

				text {
					display: block;
					padding: 20rpx;
				}
			}
		}
	}
</style>